sp_widget.client_script:
api.controller=function() {
  var c = this;

  c.prompts = [];

  // Initialize the widget
  c.$onInit = function() {
    c.prompts = c.data.prompts;
  };
};

sp_widget.css:
.prompt-list {
  margin: 20px 0;
}

.prompt-item {
  padding: 15px;
  margin-bottom: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
  background-color: #fff;
}

.prompt-number {
  font-weight: bold;
  color: #2c3e50;
}

.prompt-content {
  margin-top: 10px;
  color: #34495e;
}

.prompt-meta {
  margin-top: 10px;
  font-size: 0.9em;
  color: #7f8c8d;
}

sp_widget.script:
(function() {
  // Get all prompts that are marked for display on portal
  var gr = new GlideRecord('x_snc_ehd_promptce_prompt');
  gr.addQuery('display_on_portal', true);
  gr.orderByDesc('sys_created_on');
  gr.query();

  data.prompts = [];
  while (gr.next()) {
    data.prompts.push({
      number: gr.number.toString(),
      expanded_prompt: gr.expanded_prompt.toString(),
      user_input: gr.user_input.toString(),
      submitter: gr.submitter.getDisplayValue(),
      created_on: gr.sys_created_on.getDisplayValue()
    });
  }
})();
